content:
{
  "sentences": [
    {
      "text": "你來台灣多久了？",
      "pinyin": "Nǐ lái Táiwān duō jiǔ le?",
      "pinyin_numeric": "ni3 lai2 tai2 wan1 duo1 jiu3 le0",
      "translation_en": "How long have you been in Taiwan?",
      "translation_ko": "대만에 온 지 얼마나 되었어요?"
    },
    {
      "text": "我來台灣三個月了。",
      "pinyin": "Wǒ lái Táiwān sān ge yuè le.",
      "pinyin_numeric": "wo3 lai2 tai2 wan1 san1 ge0 yue4 le0",
      "translation_en": "I have been in Taiwan for three months.",
      "translation_ko": "저는 대만에 온 지 석 달 되었어요."
    },
    {
      "text": "我的故鄉在台北，我在這裡長大。",
      "pinyin": "Wǒ de gùxiāng zài Táiběi, wǒ zài zhèlǐ zhǎngdà.",
      "pinyin_numeric": "wo3 de0 gu4 xiang1 zai4 tai2 bei3, wo3 zai4 zhe4 li3 zhang3 da4",
      "translation_en": "My hometown is Taipei, and I grew up here.",
      "translation_ko": "제 고향은 타이베이이고, 여기서 자랐어요."
    },
    {
      "pinyin": "Wǒ shì xuéshēng, wǒ zài xuéxiào shàngkè.",
      "pinyin_numeric": "wo3 shi4 xue2 sheng1, wo3 zai4 xue2 xiao4 shang4 ke4",
      "translation_en": "I am a student, and I attend classes at school.",
      "translation_ko": "저는 학생이고, 학교에서 수업을 들어요.",
      "text": "我是學生，我在學校上課。"
    },
    {
      "pinyin": "Wǒ xiǎng xué Zhōngwén, yīnwèi wǒ xǐhuān Táiwān de wénhuà.",
      "pinyin_numeric": "wo3 xiang3 xue2 zhong1 wen2, yin1 wei4 wo3 xi3 huan1 tai2 wan1 de0 wen2 hua4",
      "translation_en": "I want to learn Chinese because I like Taiwanese culture.",
      "translation_ko": "저는 중국어를 배우고 싶어요. 대만 문화를 좋아하기 때문이에요.",
      "text": "我想學中文，因為我喜歡台灣的文化。"
    },
    {
      "pinyin": "Nǐ cóng nǎlǐ lái? Nǐ de gùxiāng shì chéngshì háishì xiāngxià?",
      "pinyin_numeric": "ni3 cong2 na3 li3 lai2? ni3 de0 gu4 xiang1 shi4 cheng2 shi4 hai2 shi4 xiang1 xia4?",
      "translation_en": "Where are you from? Is your hometown a city or the countryside?",
      "translation_ko": "어디에서 오셨어요? 고향은 도시인가요, 시골인가요?",
      "text": "你從哪裡來？你的故鄉是城市還是鄉下？"
    },
    {
      "pinyin": "Wǒ de gōngzuò shì gōngchéngshī, wǒ měitiān shàngbān.",
      "pinyin_numeric": "wo3 de0 gong1 zuo4 shi4 gong1 cheng2 shi1, wo3 mei3 tian1 shang4 ban1",
      "translation_en": "My job is an engineer, and I go to work every day.",
      "translation_ko": "제 직업은 엔지니어이고, 매일 출근해요.",
      "text": "我的工作是工程師，我每天上班。"
    },
    {
      "pinyin": "Wǒ yǐjīng xué Zhōngwén bàn nián le, wǒ xīwàng jiānglái kěyǐ shuō dé hěn liúlì.",
      "pinyin_numeric": "wo3 yi3 jing1 xue2 zhong1 wen2 ban4 nian2 le0, wo3 xi1 wang4 jiang1 lai2 ke3 yi3 shuo1 de2 hen3 liu2 li4",
      "translation_en": "I have been learning Chinese for half a year, and I hope to speak fluently in the future.",
      "translation_ko": "저는 중국어를 배운 지 반 년 되었어요. 앞으로 유창하게 말할 수 있기를 바라요.",
      "text": "我已經學中文半年了，我希望將來可以說得很流利。"
    },
    {
      "pinyin": "Nǐ de mùbiāo shì shénme? Nǐ dǎsuàn kǎoshì ma?",
      "pinyin_numeric": "ni3 de0 mu4 biao1 shi4 shen2 me0? ni3 da3 suan4 kao3 shi4 ma0?",
      "translation_en": "What is your goal? Do you plan to take an exam?",
      "translation_ko": "목표가 무엇인가요? 시험을 볼 계획인가요?",
      "text": "你的目標是什麼？你打算考試嗎？"
    },
    {
      "pinyin": "Wǒ cóng Měiguó lái, wǒ lái Táiwān liúxué, yīnwèi wǒ xiǎng xué Zhōngwén hé liǎojiě wénhuà.",
      "pinyin_numeric": "wo3 cong2 mei3 guo2 lai2, wo3 lai2 tai2 wan1 liu2 xue2, yin1 wei4 wo3 xiang3 xue2 zhong1 wen2 he2 liao3 jie3 wen2 hua4",
      "translation_en": "I come from the United States; I came to Taiwan to study abroad because I want to learn Chinese and understand the culture.",
      "translation_ko": "저는 미국에서 왔어요. 중국어를 배우고 문화를 이해하기 위해 대만에 유학 왔어요.",
      "text": "我從美國來，我來台灣留學，因為我想學中文和了解文化。"
    }
  ]
}
